INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, 14114077, 0, 14114, "vo_wac_14114", "", "vo_wac_14114_002", 21, "", "");
