INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 16614068, 1, 16614, 102711, 0, "誕生、日……？\n私のですか？\nなぜそんなことを\n覚えているのですか？", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 16614069, "", 16614, 0, "", "", 91, "", "");
