INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 1, 18814084, "", 18814, 100911, 0.2, "wac_birthday_talk_doya", 3, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, 18814085, 0, 18814, "vo_wac_18814", "", "vo_wac_18814_003", 21, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 18814086, 1, 18814, 100911, 0, "シグルドからも助言を得ている。\nナナカ生誕を祝すのにふさわしい、\n伝説級の品々を用意してあるぞ？\n限定魔法少女グッズの詰め合わせだ！", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 18814087, "", 18814, 0, "", "", 91, "", "");
