INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 1, 18814089, "", 18814, 101311, 0.2, "wac_birthday_talk_smile", 3, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, 18814090, 0, 18814, "vo_wac_18814", "", "vo_wac_18814_004", 21, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 18814091, 1, 18814, 101311, 0, "なんという僥倖ッ！\nみなさま、感謝いたしますぞ～！！\n期待に応えてこれからも、ぐうかわ\n魔法少女として邁進していくことを……", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 18814092, "", 18814, 0, "", "", 91, "", "");
