INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, 19814070, 0, 19814, "vo_wac_19814", "", "vo_wac_19814_000", 21, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 19814071, 1, 19814, 103011, 0, "このおいしそうなケーキは……ハッ！？\nワタシの命を狙う、アクダイカンの\n仕組んだトラップでショウか？", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 19814072, "", 19814, 0, "", "", 91, "", "");
