INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 1, 19814084, "", 19814, 105511, 0.2, "wac_birthday_talk_sad", 3, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, 19814085, 0, 19814, "vo_wac_19814", "", "vo_wac_19814_003", 21, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 19814086, 1, 19814, 105511, 0, "誕生日にそんなことされて喜ぶのは、\nクウカさんだけだと思います……", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 19814087, "", 19814, 0, "", "", 91, "", "");
