INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, 19814090, 0, 19814, "vo_wac_19814", "", "vo_wac_19814_004", 21, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 19814091, 1, 19814, 103011, 0, "ワタシの誕生日ケーキ！？\nそれは大変、ゴブレイしマシタ♪\n本来であればセップクものですが、\n腹よりケーキを切りまショウ♪", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 19814092, "", 19814, 0, "", "", 91, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 1, 19814093, "", 19814, 103011, 0.2, "wac_birthday_idle_smile", 3, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 1, 19814094, "", 19814, 100811, 0.2, "wac_birthday_talk_smile", 3, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, 19814095, 0, 19814, "vo_wac_19814", "", "vo_wac_19814_005", 21, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 19814096, 1, 19814, 100811, 0, "ちなみに、このケーキは美しいボクと\nギルドの仲間たち、それといつもの\nこの人で選んだんだ。主にボクの\n顔を思い浮かべつつ味わってよね♪", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 19814097, "", 19814, 0, "", "", 91, "", "");
