INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 21314060, 1, 21314, 111011, 0, "チエル君。ひと月前から騒いでおいて、\n何を今さら白々しいこと言っとるんだ。\nいいから大人しく祝われたまえ。\nハイおめちぇるー、全員拍手ー", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 21314061, "", 21314, 0, "", "", 91, "", "");
