INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 23814084, 1, 23814, 100811, 0, "どうもありがとう♪\nそれにしても素晴らしいケーキだね、\nボクのために用意してくれたの？", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 23814085, "", 23814, 0, "", "", 91, "", "");
