INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, 25214060, 0, 25214, "vo_wac_25214", "", "vo_wac_25214_001", 21, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 25214061, 1, 25214, 101111, 0, "ちょっと待ってくださいお姉ちゃん！\n私たちも手伝ってますよ！\nココとか！　ココもです！", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 25214062, "", 25214, 0, "", "", 91, "", "");
