INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 26224083, 1, 26224, 101411, 0, "そ、そんなに急かさなくても……！\nというか助手くんも来てくれたのかい？\nわざわざ祝いに来てくれるなんて、\nその……うん、すごく、うれしいよ。", 11, 0.5, 0);
