INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 1, 28414076, "", 28414, 107111, 0.2, "wac_birthday_talk_doya", 3, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, 28414077, 0, 28414, "vo_wac_28414", "", "vo_wac_28414_003", 21, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 28414078, 1, 28414, 107111, 0, "ふふん、マツリちゃんもまた一歩、\nワタシに近づいたということだ。\n良かったな、これからも\nビシバシ鍛えてやるから期待していろ♪", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 28414079, "", 28414, 0, "", "", 91, "", "");
