INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 28414083, 1, 28414, 100511, 0, "うっ……クリスティーナおばさんは\n怖いけど……みんな、ありがとうッス！\nそれにあんたも祝ってくれるなんて、\n自分はすごく幸せ者ッスよー！", 11, 0.5, 0);
