INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, 30314069, 0, 30314, "vo_wac_30314", "", "vo_wac_30314_001", 21, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 30314070, 1, 30314, 105811, 0, "お祝いするに決まってますよ～！\nシェフィちゃんは【美食殿】の大切な\n仲間なんですから♪", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 30314071, "", 30314, 0, "", "", 91, "", "");
