INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 1, 30314073, "", 30314, 106411, 0.2, "wac_birthday_talk_sad", 3, "", "");
