INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 1, 31114089, "", 31114, 104411, 0.2, "wac_birthday_talk_doya", 3, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, 31114090, 0, 31114, "vo_wac_31114", "", "vo_wac_31114_004", 21, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 31114091, 1, 31114, 104411, 0, "これ、お主たち。\nシノブの誕生日じゃというのに、\nお返しの話題で盛り上がるでないわ。\nまったく、こやつらは……", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 31114092, "", 31114, 0, "", "", 91, "", "");
