INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 1, 31114094, "", 31114, 103111, 0.2, "wac_birthday_talk_normal", 3, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, 31114095, 0, 31114, "vo_wac_31114", "", "vo_wac_31114_005", 21, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 31114096, 1, 31114, 103111, 0, "大丈夫ですよ、イリヤさん。\nいつも通りの、自由な雰囲気で\n祝ってもらう方が気も楽ですから。\nあなたも、きっとそうですよね？", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 31114097, "", 31114, 0, "", "", 91, "", "");
