INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 1, 34314074, "", 34314, 100611, 0.2, "wac_birthday_talk_smile", 3, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, 34314075, 0, 34314, "vo_wac_34314", "", "vo_wac_34314_001", 21, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 34314076, 1, 34314, 100611, 0, "もちろん、甘々で、プルプルのプリンを\nたくさん用意してきたよ～♪\n一度に頬張ったら、お口から\n垂れてきちゃうかも～♪", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 34314077, "", 34314, 0, "", "", 91, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 1, 34314078, "", 34314, 100611, 0.2, "wac_birthday_idle_smile", 3, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 1, 34314079, "", 34314, 100711, 0.2, "wac_birthday_talk_doya", 3, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, 34314080, 0, 34314, "vo_wac_34314", "", "vo_wac_34314_002", 21, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 34314081, 1, 34314, 100711, 0, "オマエたち、よくわかってるプレゼント\n本当にありがとうなの～♪\n次から誕生日だけじゃなくて、\nお盆と命日にもプリンを寄こすの～", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 34314082, "", 34314, 0, "", "", 91, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 1, 34314083, "", 34314, 100711, 0.2, "wac_birthday_idle_doya", 3, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 1, 34314084, "", 34314, 102211, 0.2, "wac_birthday_talk_sad", 3, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, 34314085, 0, 34314, "vo_wac_34314", "", "vo_wac_34314_003", 21, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 34314086, 1, 34314, 102211, 0, "ちょっと、欲張り過ぎでしょう！？\n一年に何回もこんなことしたら、\nランドソルからプリンが\n消えちゃうわよ！", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 34314087, "", 34314, 0, "", "", 91, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 1, 34314088, "", 34314, 102211, 0.2, "wac_birthday_idle_sad", 3, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 1, 34314089, "", 34314, 103111, 0.2, "wac_birthday_talk_wish", 3, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, 34314090, 0, 34314, "vo_wac_34314", "", "vo_wac_34314_004", 21, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 34314091, 1, 34314, 103111, 0, "でも、喜んでもらえてなによりです。\nミヤコさんが明るく振る舞う限り、\n穢れのない魂のまま、\n悪霊に転じることもないでしょう……", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 34314092, "", 34314, 0, "", "", 91, "", "");
