INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 1, 34414066, "", 34414, 105411, 0.2, "wac_birthday_talk_wish", 3, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, 34414067, 0, 34414, "vo_wac_34414", "", "vo_wac_34414_002", 21, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 34414068, 1, 34414, 105411, 0, "お返しって考えたらどうでしょう？\nほら、今回も騎士さんにケーキの\n用意とか手伝ってもらいましたし。\nアイドルらしいお礼になりませんか？", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 34414069, "", 34414, 0, "", "", 91, "", "");
