INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 34414073, 1, 34414, 102911, 0, "ツムギ、いいこと言うじゃない♪\nそれじゃあ感謝の気持ちを込めて……\nキミのためのバースデーライブ、\n開催しちゃおうかな♪", 11, 0.5, 0);
