INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 1, 35314071, "", 35314, 102011, 0.2, "wac_birthday_talk_smile", 3, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, 35314072, 0, 35314, "vo_wac_35314", "", "vo_wac_35314_003", 21, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 35314073, 1, 35314, 102011, 0, "大丈夫だよ、キョウカちゃん。\nミミたちも、おにいちゃんも、\nキョウカちゃんがよろこんでくれたら、\nそれだけでうれしいよ♪", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 35314074, "", 35314, 0, "", "", 91, "", "");
