INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 35314078, 1, 35314, 103611, 0, "……うん、わかった。\nまた誰かのお誕生日が来たら、\nこうやってお祝いしようね♪\nそれが一番のお返しになると思うから。", 11, 0.5, 0);
