INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 38214085, 1, 38214, 105211, 0, "そうそう。\n難しい顔するより、\nみんなで楽しくおいしくケーキを\n食べましょう♪", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 38214086, "", 38214, 0, "", "", 91, "", "");
