INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, 39114067, 0, 39114, "vo_wac_39114", "", "vo_wac_39114_001", 21, "", "");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 39114068, 1, 39114, 104611, 0, "当然のことをしたまでにゃ♪\nアキノとは【メルクリウス財団】の\n仲間として、一緒に苦労してきたにゃ。", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 39114069, "", 39114, 0, "", "", 91, "", "");
