INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (1, 10, 39114078, 1, 39114, 103411, 0, "麦しゅわの助けも借りながら、\nみんなで協力して、\n全部乗り越えることができたもの！", 11, 0.5, 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", 39114079, "", 39114, 0, "", "", 91, "", "");
